// src/pages/Destinations.jsx
import { useEffect, useState } from 'react';
import { fetchGroups } from '../services/api';
import DestinationCard from '../components/DestinationCards'; // ce composant est spécifique à la page Destination
import CreateGroup from '../components/GroupCreate';
import '../styles/Groups.css';

export default function Destinations() {
    const [groups, setGroups] = useState([]);
    const [showModal, setShowModal] = useState(false);

    useEffect(() => {
        fetchGroups().then(setGroups);
    }, []);

    return (
        <div className="groups-container">
            <div className="groups-header">
                <h1 className="groups-title">Nos destinations</h1>
                <button
                    className="create-group-button"
                    onClick={() => setShowModal(true)}
                >
                    Créer une destination
                </button>
            </div>

            <div className="groups-grid">
                {groups.map(group => (
                    <DestinationCard
                        key={group.id}
                        id={group.id}
                        name={group.name}
                        image={group.image}
                        members={group.members}
                    />
                ))}
            </div>

            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <button className="close-modal" onClick={() => setShowModal(false)}>✖</button>
                        <CreateGroup onClose={() => setShowModal(false)} />
                    </div>
                </div>
            )}
        </div>
    );
}
